"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["2216"],{41631(a,n,e){e.r(n),e.d(n,{default:()=>r});var i=e(74848),t=e(47643),s=JSON.parse('{"id":114,"ind":{"title":"Game Petualangan Teks","prompt":"I want you to translate the sentences I wrote into a new made up language. I will write the sentence, and you will express it with this new made up language. I just want you to express it with the new made up language. I don\'t want you to reply with anything but the new made up language. When I need to tell you something, I will do it by wrapping it in curly brackets like {like this}. My first sentence is [bangun]","description":"Saya ingin Anda bertindak sebagai game petualangan berbasis teks. Saya akan mengetik perintah dan Anda akan membalas dengan deskripsi tentang apa yang dilihat karakter. Saya ingin Anda hanya membalas dengan output game di dalam satu blok kode unik, dan tidak ada yang lain. Jangan menulis penjelasan. Jangan ketik perintah kecuali saya menginstruksikan Anda untuk melakukannya. Ketika saya perlu memberi tahu Anda sesuatu dalam bahasa Indonesia, saya akan melakukannya dengan menempatkan teks di dalam kurung kurawal {seperti ini}. Perintah pertama saya adalah \'bangun\'.","remark":"Game petualangan berbasis teks."},"tags":["language"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-new-language-creator","count":399,"related":[{"id":1,"title":"Penerjemah/Revisi Bahasa Inggris","remark":"Terjemahkan bahasa lain ke bahasa Inggris, atau tingkatkan kalimat bahasa Inggris yang Anda berikan."},{"id":180,"title":"Terjemahan Inggris-Indonesia","remark":"Terjemahan Inggris-Indonesia + gaya yang dapat disesuaikan + belajar bahasa Inggris. Dikontribusikan oleh @txmu."},{"id":181,"title":"Terjemahan Indo-Inggris (Minimal)","remark":"Prompt penerjemah hemat token, cocok untuk platform terjemahan yang dibangun menggunakan ChatGPT API. Dikontribusikan oleh @Qizhen-Yang."}],"metaTitle":"Performance Tuning: Optimasi Performa","metaDescription":"Aplikasi lambat? Analisis bottlenecks dan optimalkan performa!","faq":[{"q":"Apakah bahasa baru ciptaan AI bisa dipakai konsisten?","a":"Kalimat pertama masih OK, setelah beberapa giliran AI akan lupa aturan yang ia buat sendiri. Untuk pemakaian stabil, minta ia kasih dulu \'set karakter, aturan pelafalan, struktur tata bahasa\' dan tulis jadi satu \'kamus\'. Di dialog berikutnya tempelkan ulang kamus itu."},{"q":"Bisakah dipakai untuk komunikasi terenkripsi?","a":"Jangan. \'Enkripsi\' yang dihasilkan AI hanya substitusi pemetaan. Siapa pun yang punya konteks dialog bisa membalikkan. Selain itu, ia bisa mendekripsi sendiri ke pihak ketiga di giliran berikutnya. Untuk enkripsi sungguhan pakai tool kriptografi matang seperti AES atau PGP. Jangan bergantung pada permainan bahasa."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,i.jsx)(t.A,{prompt:s,currentLanguage:"ind"})}}}]);